const Service={path:"/skypass",apiPath:"/skypass/admin"};class RequestApi{static setHeaders(e){return"POST"!==e.method&&"PUT"!==e.method&&"DELETE"!==e.method||(e.body instanceof FormData?e.headers={Accept:"application/json",...e.headers}:(e.headers={Accept:"application/json","Content-Type":"application/json; charset=utf-8",...e.headers},e.body=JSON.stringify(e.body))),e}static fetch(e,t){NProgress.start();const s=RequestApi.setHeaders({...t});return fetch(Service.apiPath+e,s).then(e=>e.json()).catch(e=>(console.warn(e),e)).finally(e=>{NProgress.done()})}static fetchText(e,t){const s=Service.apiPath+e;return NProgress.start(),fetch(s,t).then(e=>e.text()).catch(e=>(console.warn(e),e)).finally(e=>{NProgress.done()})}}